import{_ as e,o as a,c as d,ag as r}from"./chunks/framework.DTiDeF2Q.js";const b=JSON.parse('{"title":"اختصارات Interactive: أوامر شل آمنة مع مطالبات التأكيد | Dotfiles (AR)","titleTemplate":":title","description":"اختصارات شل تضيف مطالبات تفاعلية قبل العمليات المدمرة مثل rm وmv وcp. منع حذف الملفات بالخطأ. متوافق مع macOS وLinux وWSL عبر Dotfiles.","frontmatter":{"title":"اختصارات Interactive: أوامر شل آمنة مع مطالبات التأكيد","description":"اختصارات شل تضيف مطالبات تفاعلية قبل العمليات المدمرة مثل rm وmv وcp. منع حذف الملفات بالخطأ. متوافق مع macOS وLinux وWSL عبر Dotfiles.","lang":"ar-SA","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"اختصارات Interactive: أوامر شل آمنة مع مطالبات التأكيد preview","canonical":"/ar/aliases/interactive/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"اختصارات Interactive: أوامر شل آمنة مع مطالبات التأكيد","pageType":"docs","schemaType":"WebPage","metaTitle":"اختصارات Interactive | Dotfiles","permalink":"/ar/aliases/interactive/","sidebar":true,"meta":[{"name":"keywords","content":"interactive aliases, shell safety, rm confirmation, cp interactive, mv prompt, dotfiles, bash aliases"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"اختصارات Interactive | Dotfiles"},{"name":"twitter:description","content":"اختصارات شل تضيف مطالبات تفاعلية قبل العمليات المدمرة مثل rm وmv وcp."},{"name":"og:title","content":"اختصارات Interactive | Dotfiles"},{"name":"og:description","content":"اختصارات شل تضيف مطالبات تفاعلية قبل العمليات المدمرة مثل rm وmv وcp."},{"name":"og:image:alt","content":"Dotfiles - مصمم ببساطة ليناسب حياتك مع الشل"},{"name":"og:locale","content":"ar_SA"}]},"headers":[],"relativePath":"ar/aliases/interactive/index.md","filePath":"ar/aliases/interactive/index.md","lastUpdated":1773010926000}'),i={name:"ar/aliases/interactive/index.md"};function o(n,t,c,l,s,h){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="اختصارات-interactive" tabindex="-1">اختصارات Interactive <a class="header-anchor" href="#اختصارات-interactive" aria-label="Permalink to &quot;اختصارات Interactive&quot;">​</a></h1><p>أوامر شل آمنة مع مطالبات تأكيد قبل العمليات المدمرة.</p><h2 id="نظرة-عامة" tabindex="-1">نظرة عامة <a class="header-anchor" href="#نظرة-عامة" aria-label="Permalink to &quot;نظرة عامة&quot;">​</a></h2><p>تضيف اختصارات Interactive مطالبات تأكيد لأوامر الشل الشائعة التي يمكنها تعديل أو حذف الملفات بشكل دائم. معرّفة في <code>interactive.aliases.sh</code> ويتم تحميلها تلقائيًا بواسطة chezmoi، تساعد هذه الاختصارات في منع فقدان البيانات عن طريق الخطأ من خلال طلب تأكيد المستخدم قبل تنفيذ العمليات الخطيرة المحتملة.</p><h2 id="المرجع" tabindex="-1">المرجع <a class="header-anchor" href="#المرجع" aria-label="Permalink to &quot;المرجع&quot;">​</a></h2><h3 id="عمليات-الملفات" tabindex="-1">عمليات الملفات <a class="header-anchor" href="#عمليات-الملفات" aria-label="Permalink to &quot;عمليات الملفات&quot;">​</a></h3><table tabindex="0"><thead><tr><th>الاختصار</th><th>الوصف</th></tr></thead><tbody><tr><td><code>cp</code></td><td>نسخ الملفات والمجلدات تفاعليًا مع مخرجات مفصلة. يطالب قبل الكتابة فوق الملفات الموجودة.</td></tr><tr><td><code>mv</code></td><td>نقل أو إعادة تسمية الملفات تفاعليًا مع مخرجات مفصلة. يطالب قبل الكتابة فوق الملفات الموجودة.</td></tr><tr><td><code>ln</code></td><td>إنشاء روابط رمزية تفاعليًا مع مخرجات مفصلة. يطالب قبل الكتابة فوق الروابط الموجودة.</td></tr></tbody></table><h3 id="إزالة-الملفات" tabindex="-1">إزالة الملفات <a class="header-anchor" href="#إزالة-الملفات" aria-label="Permalink to &quot;إزالة الملفات&quot;">​</a></h3><table tabindex="0"><thead><tr><th>الاختصار</th><th>الوصف</th></tr></thead><tbody><tr><td><code>rm</code></td><td>إزالة الملفات أو المجلدات تفاعليًا مع مخرجات مفصلة. يطالب قبل كل إزالة.</td></tr><tr><td><code>del</code></td><td>إزالة الملفات أو المجلدات تفاعليًا وتكراريًا مع مخرجات مفصلة. يطالب قبل كل إزالة.</td></tr><tr><td><code>zap</code></td><td>اختصار لـ <code>rm</code>. يزيل الملفات أو المجلدات تفاعليًا مع مخرجات مفصلة.</td></tr></tbody></table><h3 id="إدارة-سلة-المهملات" tabindex="-1">إدارة سلة المهملات <a class="header-anchor" href="#إدارة-سلة-المهملات" aria-label="Permalink to &quot;إدارة سلة المهملات&quot;">​</a></h3><table tabindex="0"><thead><tr><th>الاختصار</th><th>الوصف</th></tr></thead><tbody><tr><td><code>bin</code></td><td>إزالة جميع الملفات في مجلد سلة المهملات (<code>~/.Trash</code>) بقوة وتكراريًا.</td></tr></tbody></table><h3 id="الصلاحيات-والأدوات" tabindex="-1">الصلاحيات والأدوات <a class="header-anchor" href="#الصلاحيات-والأدوات" aria-label="Permalink to &quot;الصلاحيات والأدوات&quot;">​</a></h3><table tabindex="0"><thead><tr><th>الاختصار</th><th>الوصف</th></tr></thead><tbody><tr><td><code>chmod</code></td><td>تغيير صلاحيات الملف أو المجلد مع مخرجات مفصلة.</td></tr><tr><td><code>chown</code></td><td>تغيير مالك ومجموعة الملف أو المجلد مع مخرجات مفصلة.</td></tr><tr><td><code>diff</code></td><td>مقارنة وعرض الفروقات بين ملفين بتنسيق موحد.</td></tr><tr><td><code>grep</code></td><td>البحث عن نمط في الملفات أو المخرجات، مع عرض أرقام الأسطر وبدون حساسية لحالة الأحرف.</td></tr><tr><td><code>mkdir</code></td><td>إنشاء مجلد جديد مع المجلدات الأب حسب الحاجة ومخرجات مفصلة.</td></tr></tbody></table>',13)])])}const p=e(i,[["render",o]]);export{b as __pageData,p as default};
